// Some portions generated by Co-Pilot
import React from "react";
import { render, screen, cleanup } from "@testing-library/react";
import { describe, it, expect, vi, afterEach, beforeEach } from "vitest";

// Provide a stub WebGL context for canvas in jsdom
const mockGetContext = vi.fn().mockReturnValue({
  getExtension: vi.fn().mockReturnValue(null),
  getParameter: vi.fn().mockReturnValue(""),
});
HTMLCanvasElement.prototype.getContext = mockGetContext;

vi.mock("@/utils/detectOS", () => ({
  detectOS: vi.fn(),
  UserOS: { MAC: 0, LINUX: 1, WIN: 2, UNIX: 3 },
}));

vi.mock("@/hooks", () => ({
  useFetchLatestForOS: vi.fn(),
  useOnScreen: vi.fn().mockReturnValue(true),
}));

vi.mock("@/utils/gtag", () => ({
  sendDownloadEvent: vi.fn(),
}));

vi.mock("./OSIcon", () => ({
  default: ({ os }: { os: number }) => (
    <div data-testid="os-icon" data-os={os} />
  ),
}));

import DownloadButton from "../DownloadButton";
import { detectOS, UserOS } from "@/utils/detectOS";
import { useFetchLatestForOS } from "@/hooks";

const mockBinary = {
  type: "jdk",
  link: "https://example.com/jdk-21.tar.gz",
  checksum: "abc123",
  size: 123456789,
  extension: "tar.gz",
  release_name: "jdk-21+35",
};

describe("DownloadButton", () => {
  afterEach(() => {
    cleanup();
    vi.clearAllMocks();
  });

  it("renders loading state when binary is not available", () => {
    vi.mocked(detectOS).mockReturnValue(UserOS.WIN);
    vi.mocked(useFetchLatestForOS).mockReturnValue(null);
    render(<DownloadButton latestLTS={21} />);
    // Should render some text (translation mocked as "Text")
    expect(screen.getAllByText("Text").length).toBeGreaterThan(0);
  });

  it("renders download button when binary is available for Windows", () => {
    vi.mocked(detectOS).mockReturnValue(UserOS.WIN);
    vi.mocked(useFetchLatestForOS).mockReturnValue(mockBinary);
    render(<DownloadButton latestLTS={21} />);
    expect(screen.getAllByText("Text").length).toBeGreaterThan(0);
  });

  it("renders download button for Linux", () => {
    vi.mocked(detectOS).mockReturnValue(UserOS.LINUX);
    vi.mocked(useFetchLatestForOS).mockReturnValue(mockBinary);
    render(<DownloadButton latestLTS={21} />);
    expect(screen.getAllByText("Text").length).toBeGreaterThan(0);
  });

  it("renders download button for UNIX", () => {
    vi.mocked(detectOS).mockReturnValue(UserOS.UNIX);
    vi.mocked(useFetchLatestForOS).mockReturnValue(mockBinary);
    render(<DownloadButton latestLTS={21} />);
    expect(screen.getAllByText("Text").length).toBeGreaterThan(0);
  });

  it("renders for Mac without binary", () => {
    vi.mocked(detectOS).mockReturnValue(UserOS.MAC);
    vi.mocked(useFetchLatestForOS).mockReturnValue(null);
    render(<DownloadButton latestLTS={17} />);
    expect(screen.getAllByText("Text").length).toBeGreaterThan(0);
  });

  it("renders other-downloads link", () => {
    vi.mocked(detectOS).mockReturnValue(UserOS.WIN);
    vi.mocked(useFetchLatestForOS).mockReturnValue(mockBinary);
    render(<DownloadButton latestLTS={21} />);
    const links = screen.getAllByRole("link");
    const releasesLink = links.find(
      (l) => l.getAttribute("href") === "/temurin/releases",
    );
    expect(releasesLink).toBeTruthy();
  });

  it("renders with default OS when detectOS returns undefined", () => {
    vi.mocked(detectOS).mockReturnValue(undefined as any);
    vi.mocked(useFetchLatestForOS).mockReturnValue(null);
    render(<DownloadButton latestLTS={21} />);
    expect(screen.getAllByText("Text").length).toBeGreaterThan(0);
  });
});
